#include <stdio.h>
#define MAX_SIZE 1000

int is_sum(int x, int a[],int n);

int main() {
    int i, target_num, size_array, array[MAX_SIZE];
    scanf("%d",&size_array);
    for(i=0;i<size_array;i++)
        scanf("%d",&array[i]);
    scanf("%d",&target_num);
    printf("%d",is_sum(target_num,array,size_array));
    return 0;
}

int is_sum(int x, int a[], int n)
{
    if (x==0)
        return 1; /* return success if reached sum */
    else if (n<=0)
        return 0; /* return fail if not we're out of array bounds */

    return (is_sum(x-a[0], a+2, n-2)) || (is_sum(x-a[1], a+3, n-3));
}

#include <stdio.h>
void print_base_2(int num);
int main() {
    int x;
    scanf("%d",&x);
    print_base_2(x);
    return 0;
}
void print_base_2(int num)
{
    int reminder, div;
    reminder = num % 2;
    div = num / 2;

    printf("%d", reminder);
    if (div == 0)
        printf("-");
    else
        print_base_2(div);
    printf("%d", reminder);
}
